                    (poly['superficie_en_ha'] as num?)?.toDouble() ?? 0.0,
                nbSommets: points.length,
                enqueteur: poly['enqueteur']?.toString() ?? '',
                dateCreation: poly['date_creation']?.toString() ?? '----',
                synced: poly['synced'] == 1,
                downloaded: poly['downloaded'] == 1,
