        if (formResult != null) {
          // NETTOYER TOUTES les sources de polylines pour ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â©viter les doublons
          setState(() {
