  Color getChausseeColor(String type) {
    switch (type.toLowerCase()) {
      case 'bitume':
        return Colors.black;
      case 'terre':
        return const Color(0xFFD2691E);
      case 'latÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â©rite':
        return Colors.red.shade700;
      case 'bouwal':
      case 'bowal':
        return Colors.yellow.shade700;
      case 'dÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â©viation':
      case 'deviation':
        return Colors.orange.shade700;
      case 'coupure':
        return Colors.deepPurple;
      case 'submersible':
        return Colors.teal;
      case 'col':
        return Colors.green.shade800;
      default:
        return Colors.blueGrey;
    }
  }

  Future<void> finishChausseeCollection() async {
    final result = homeController.finishChausseeCollection();
    if (result == null) {
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(
        const SnackBar(
          content: Text(
            "Une chaussÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â©e doit contenir au moins 2 points.",
          ),
        ),
      );
      return;
    }

    // Ouvrir le formulaire principal avec les donnÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â©es provisoires
    final formResult = await Navigator.push(
      context,
      MaterialPageRoute(
        builder: (
          _,
        ) =>
            FormulaireChausseePage(
          chausseePoints: result['points'],
          provisionalId: result['id'],
          agentName: widget.agentName,
          nearestPisteCode: _currentNearestPisteCode, // ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã¢â‚¬Â¦ÃƒÂ¢Ã¢â€šÂ¬Ã…â€œÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚Â¦ Utiliser l'ID correct
        ),
      ),
    );

    if (formResult != null) {
      final List<LatLng> pts = List<LatLng>.from(result['points'] as List<LatLng>);
      final distanceKm = pts.length >= 2 ? polylineDistanceKm(pts) : 0.0;
      final typeChaussee = (formResult['type_chaussee'] ?? 'inconnu').toString();
      final endroit = (formResult['endroit'] ?? '').toString();
      final codePiste = (formResult['code_piste'] ?? '').toString();

      setState(
        () {
          _finishedChaussees.add(
            Polyline<PolylineTapData>(
              points: pts,
              color: getChausseeColor(typeChaussee),
              strokeWidth: 4.0,
              pattern: getChausseePattern(typeChaussee) ?? const StrokePattern.solid(),
              hitValue: PolylineTapData(
                type: 'chaussee_local',
                data: {
                  'type_chaussee': typeChaussee,
                  'endroit': endroit,
                  'code_piste': codePiste,
                  'nb_points': pts.length,
                  'distance_km': distanceKm,
                  'start_lat': pts.first.latitude,
                  'start_lng': pts.first.longitude,
                  'end_lat': pts.last.latitude,
                  'end_lng': pts.last.longitude,
                  'synced': '0',
                  'region_name': '',
                  'prefecture_name': '',
                  'commune_name': '',
                  'enqueteur': formResult['user_login'] ?? widget.agentName ?? '',
                },
              ),
            ),
          );
        },
      );
      final storageHelper = SimpleStorageHelper();
      await storageHelper.saveDisplayedChaussee(
        pts,
        typeChaussee,
        4.0,
        codePiste,
        endroit,
      );

      ScaffoldMessenger.of(
        context,
      ).showSnackBar(
        const SnackBar(
          content: Text(
            'ChaussÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â©e enregistrÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â©e avec succÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¨s',
          ),
          backgroundColor: Colors.green,
        ),
      );
    }
  }

